  1→import { PUBLIC_API_BASE } from '$env/static/public';
  2→
  3→const TOKEN_KEY = 'aileron_access_token';
  4→const REFRESH_KEY = 'aileron_refresh_token';
  5→
  6→/** Reactive auth state using Svelte 5 runes via module-level $state. */
  7→let _token = $state<string | null>(null);
  8→let _user = $state<AuthUser | null>(null);
  9→
 10→export interface AuthUser {
 11→	id: string;
 12→	email: string;
 13→	display_name: string;
 14→	avatar_url?: string;
 15→	role: string;
 16→	enterprise_id: string;
 17→}
 18→
 19→/** Initialize auth state from localStorage (call once on app mount). */
 20→export function initAuth() {
 21→	if (typeof window === 'undefined') return;
 22→	_token = localStorage.getItem(TOKEN_KEY);
 23→	if (_token) {
 24→		fetchCurrentUser().catch(() => clearAuth());
 25→	}
 26→}
 27→
 28→/** Returns the current access token, or null. */
 29→export function getToken(): string | null {
 30→	return _token;
 31→}
 32→
 33→/** Returns the current user, or null. */
 34→export function getUser(): AuthUser | null {
 35→	return _user;
 36→}
 37→
 38→/** Returns true if the user is authenticated. */
 39→export function isAuthenticated(): boolean {
 40→	return _token !== null;
 41→}
 42→
 43→/** Store tokens after login/signup and fetch user profile. */
 44→export async function setAuth(accessToken: string, refreshToken?: string) {
 45→	_token = accessToken;
 46→	localStorage.setItem(TOKEN_KEY, accessToken);
 47→	if (refreshToken) {
 48→		localStorage.setItem(REFRESH_KEY, refreshToken);
 49→	}
 50→	await fetchCurrentUser();
 51→}
 52→
 53→/** Clear auth state (logout). */
 54→export function clearAuth() {
 55→	_token = null;
 56→	_user = null;
 57→	localStorage.removeItem(TOKEN_KEY);
 58→	localStorage.removeItem(REFRESH_KEY);
 59→}
 60→
 61→/** Attempt to refresh the access token using the stored refresh token. */
 62→export async function refreshAuth(): Promise<boolean> {
 63→	const refreshToken = localStorage.getItem(REFRESH_KEY);
 64→	if (!refreshToken) return false;
 65→
 66→	try {
 67→		const res = await fetch(`${PUBLIC_API_BASE}/auth/refresh`, {
 68→			method: 'POST',
 69→			credentials: 'include',
 70→			headers: { 'Content-Type': 'application/json' },
 71→			body: JSON.stringify({ refresh_token: refreshToken })
 72→		});
 73→		if (!res.ok) {
 74→			clearAuth();
 75→			return false;
 76→		}
 77→		const data = await res.json();
 78→		_token = data.access_token;
 79→		localStorage.setItem(TOKEN_KEY, data.access_token);
 80→		return true;
 81→	} catch {
 82→		clearAuth();
 83→		return false;
 84→	}
 85→}
 86→
 87→/** Fetch the current user profile from /v1/users/me. */
 88→async function fetchCurrentUser() {
 89→	const headers: Record<string, string> = {};
 90→	// Use Bearer token for password-based auth; use cookies for OAuth flow.
 91→	if (_token && _token !== 'cookie-auth') {
 92→		headers['Authorization'] = `Bearer ${_token}`;
 93→	}
 94→	const res = await fetch(`${PUBLIC_API_BASE}/v1/users/me`, {
 95→		headers,
 96→		credentials: 'include'
 97→	});
 98→	if (!res.ok) throw new Error('Failed to fetch user');
 99→	_user = await res.json();
100→}
101→
102→// --- Auth API calls (signup, login, verify) ---
103→
104→export async function signup(email: string, password: string, displayName?: string) {
105→	const res = await fetch(`${PUBLIC_API_BASE}/auth/signup`, {
106→		method: 'POST',
107→		headers: { 'Content-Type': 'application/json' },
108→		body: JSON.stringify({ email, password, display_name: displayName })
109→	});
110→	if (!res.ok) {
111→		const err = await res.json().catch(() => ({ error: res.statusText }));
112→		throw new Error(err.error || res.statusText);
113→	}
114→	return res.json();
115→}
116→
117→export async function verifyEmail(email: string, code: string) {
118→	const res = await fetch(`${PUBLIC_API_BASE}/auth/verify-email`, {
119→		method: 'POST',
120→		headers: { 'Content-Type': 'application/json' },
121→		body: JSON.stringify({ email, code })
122→	});
123→	if (!res.ok) {
124→		const err = await res.json().catch(() => ({ error: res.statusText }));
125→		throw new Error(err.error || res.statusText);
126→	}
127→	return res.json();
128→}
129→
130→export async function emailLogin(email: string, password: string) {
131→	const res = await fetch(`${PUBLIC_API_BASE}/auth/login`, {
132→		method: 'POST',
133→		headers: { 'Content-Type': 'application/json' },
134→		body: JSON.stringify({ email, password })
135→	});
136→	if (!res.ok) {
137→		const err = await res.json().catch(() => ({ error: res.statusText }));
138→		throw new Error(err.error || res.statusText);
139→	}
140→	return res.json();
141→}
142→
143→export async function logout() {
144→	try {
145→		await fetch(`${PUBLIC_API_BASE}/auth/logout`, {
146→			method: 'POST',
147→			headers: _token ? { Authorization: `Bearer ${_token}` } : {}
148→		});
149→	} catch {
150→		// Best-effort server-side logout.
151→	}
152→	clearAuth();
153→}
