 1→<script lang="ts">
 2→	import { goto } from '$app/navigation';
 3→	import { PUBLIC_API_BASE } from '$env/static/public';
 4→	import { setAuth } from '$lib/auth.svelte.js';
 5→	import { onMount } from 'svelte';
 6→
 7→	let error = $state('');
 8→
 9→	onMount(async () => {
10→		try {
11→			// After OAuth redirect, the server set httpOnly cookies.
12→			// Fetch user profile using cookie auth to bootstrap the session.
13→			const res = await fetch(`${PUBLIC_API_BASE}/v1/users/me`, {
14→				credentials: 'include'
15→			});
16→			if (!res.ok) throw new Error('Failed to load session');
17→
18→			// Extract the access token from the cookie if available,
19→			// otherwise the cookie-based auth will work for API calls.
20→			// Store a marker so the auth store knows we're logged in.
21→			await setAuth('cookie-auth');
22→			goto('/');
23→		} catch (err: any) {
24→			error = err.message || 'Authentication failed';
25→		}
26→	});
27→</script>
