 3→import (
 4→	"net/http"
 5→
 6→	"github.com/ALRubinger/aileron/core/auth"
 7→)
 8→
 9→// GetCurrentEnterprise and GetCurrentUser are generated ServerInterface
10→// methods for the Enterprises and Users tags. Auth endpoints (Auth tag)
11→// are excluded from code generation and handled by core/auth.Handler.
12→
13→func (s *apiServer) GetCurrentEnterprise(w http.ResponseWriter, r *http.Request) {
14→	claims := auth.ClaimsFromContext(r.Context())
15→	if claims == nil {
16→		http.Error(w, `{"error":"not authenticated"}`, http.StatusUnauthorized)
17→		return
18→	}
19→
20→	if s.enterprises == nil {
21→		http.Error(w, `{"error":"auth not enabled"}`, http.StatusNotImplemented)
22→		return
23→	}
24→
25→	ent, err := s.enterprises.Get(r.Context(), claims.EnterpriseID)
26→	if err != nil {
27→		http.Error(w, `{"error":"enterprise not found"}`, http.StatusNotFound)
28→		return
29→	}
30→	writeJSON(w, http.StatusOK, ent)
31→}
32→
33→func (s *apiServer) GetCurrentUser(w http.ResponseWriter, r *http.Request) {
34→	claims := auth.ClaimsFromContext(r.Context())
35→	if claims == nil {
36→		http.Error(w, `{"error":"not authenticated"}`, http.StatusUnauthorized)
37→		return
38→	}
39→
40→	if s.users == nil {
41→		http.Error(w, `{"error":"auth not enabled"}`, http.StatusNotImplemented)
42→		return
43→	}
44→
45→	user, err := s.users.Get(r.Context(), claims.Subject)
46→	if err != nil {
47→		http.Error(w, `{"error":"user not found"}`, http.StatusNotFound)
48→		return
49→	}
50→	writeJSON(w, http.StatusOK, user)
51→}
